local xml = require("luaxml")

local function parse_xml_request(ngx)
    local request_body = ngx.req.read_body()
    local parsed_xml, err = xml.parse(request_body)

    if not parsed_xml then
        ngx.status = 400
        ngx.say("Error parsing XML request: ", err)
        ngx.exit(400)
    end

    -- Extract data from parsed XML
    local request_data = {
        operation = parsed_xml.operation,
        parameters = parsed_xml.parameters,
    }

    return request_data
end

